-- 更新时间戳函数
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ language 'plpgsql';

-- 为需要的表创建触发器（使用 DROP IF EXISTS 保证幂等，可安全重复执行）
DO $$ BEGIN
    DROP TRIGGER IF EXISTS update_users_updated_at ON users;
    CREATE TRIGGER update_users_updated_at BEFORE UPDATE ON users FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
END $$;
DO $$ BEGIN
    DROP TRIGGER IF EXISTS update_stations_updated_at ON stations;
    CREATE TRIGGER update_stations_updated_at BEFORE UPDATE ON stations FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
END $$;
DO $$ BEGIN
    DROP TRIGGER IF EXISTS update_devices_updated_at ON devices;
    CREATE TRIGGER update_devices_updated_at BEFORE UPDATE ON devices FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
END $$;
DO $$ BEGIN
    DROP TRIGGER IF EXISTS update_system_configs_updated_at ON system_configs;
    CREATE TRIGGER update_system_configs_updated_at BEFORE UPDATE ON system_configs FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
END $$;

-- alarms 兼容列同步触发器 (migration 027+039)
-- 保持 alarm_level↔level、fault_message↔message 同步，验证 status/event_state 枚举值
CREATE OR REPLACE FUNCTION normalize_alarms_compat_columns()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.status NOT IN (0, 1, 2) THEN
        RAISE EXCEPTION 'alarms.status must be 0 (unhandled), 1 (handled), or 2 (ignored)'
            USING ERRCODE = '23514';
    END IF;
    IF NEW.event_state NOT IN ('active', 'recovered') THEN
        RAISE EXCEPTION 'alarms.event_state must be active or recovered'
            USING ERRCODE = '23514';
    END IF;
    NEW.alarm_level := COALESCE(NEW.alarm_level, NEW.level);
    NEW.level := NEW.alarm_level;
    NEW.fault_message := COALESCE(NULLIF(NEW.fault_message, ''), NEW.message, '');
    NEW.message := NEW.fault_message;
    NEW.type := COALESCE(NULLIF(NEW.type, ''), 'device_fault');
    NEW.updated_at := NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DO $$ BEGIN
    DROP TRIGGER IF EXISTS trg_alarms_compat_columns ON alarms;
    CREATE TRIGGER trg_alarms_compat_columns
    BEFORE INSERT OR UPDATE ON alarms
    FOR EACH ROW EXECUTE FUNCTION normalize_alarms_compat_columns();
END $$;

-- 设备时区同步函数 (migration 031)
-- 设备 station_id 变更时自动从电站同步时区
CREATE OR REPLACE FUNCTION sync_device_timezone()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.station_id IS NOT NULL AND (OLD.station_id IS NULL OR OLD.station_id != NEW.station_id) THEN
        NEW.timezone := COALESCE(
            (SELECT s.timezone FROM stations s WHERE s.id = NEW.station_id),
            'Asia/Shanghai'
        );
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_sync_device_timezone ON devices;
CREATE TRIGGER trg_sync_device_timezone
    BEFORE INSERT OR UPDATE OF station_id ON devices
    FOR EACH ROW EXECUTE FUNCTION sync_device_timezone();

-- 告警兼容列规范化函数 (migration 039)
-- 在 INSERT/UPDATE 前同步 alarm_level<->level、fault_message<->message，
-- 校验 status 和 event_state 枚举值，并自动填充 type 和 updated_at。
CREATE OR REPLACE FUNCTION normalize_alarms_compat_columns()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.status NOT IN (0, 1, 2) THEN
        RAISE EXCEPTION 'alarms.status must be 0 (unhandled), 1 (handled), or 2 (ignored)'
            USING ERRCODE = '23514';
    END IF;
    IF NEW.event_state NOT IN ('active', 'recovered') THEN
        RAISE EXCEPTION 'alarms.event_state must be active or recovered'
            USING ERRCODE = '23514';
    END IF;
    NEW.alarm_level := COALESCE(NEW.alarm_level, NEW.level);
    NEW.level := NEW.alarm_level;
    NEW.fault_message := COALESCE(NULLIF(NEW.fault_message, ''), NEW.message, '');
    NEW.message := NEW.fault_message;
    NEW.type := COALESCE(NULLIF(NEW.type, ''), 'device_fault');
    NEW.updated_at := NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_alarms_compat_columns ON alarms;
CREATE TRIGGER trg_alarms_compat_columns
    BEFORE INSERT OR UPDATE ON alarms
    FOR EACH ROW EXECUTE FUNCTION normalize_alarms_compat_columns();

-- 清理过期数据函数
CREATE OR REPLACE FUNCTION clean_expired_data()
RETURNS void AS $$
BEGIN
    -- 清理过期验证码
    DELETE FROM verification_codes WHERE expires_at < NOW();
    -- 注意：时序数据由 TimescaleDB 自动管理
    -- user_sessions 已删除（改用 JWT）
END;
$$ LANGUAGE plpgsql;

