        f.group_code||':'||f.field_index||':'||f.field_key||':'||f.wire_type||':'||
        COALESCE(f.minimum::text,'')||':'||COALESCE(f.maximum::text,''),',' ORDER BY f.group_code,f.field_index
    ),'UTF8')),'hex')
