-- ---------- Migration 31: 031_add_missing_schema_objects.up.sql ----------
-- 031_add_missing_schema_objects: 补齐代码中引用但缺少迁移文件的数据库对象
-- 涵盖三个对象：
--   1. devices.model_id 列（Go 代码多处引用，如 telemetry_repository.go、model_registry_repository.go）
--   2. user_device_rel 表（Go 代码 8 处引用，如 repositories.go、ota_repository.go、dashboard_handler.go）
--   3. sync_device_timezone() 函数及触发器（生产备份 schema 中存在，用于设备时区与电站时区同步）
-- 所有 DDL 使用 IF NOT EXISTS / CREATE OR REPLACE 确保幂等性

-- ============================================
-- 1. devices.model_id 列
-- ============================================
-- 关联 device_models 表，Go 代码通过 d.model_id 进行型号关联查询
ALTER TABLE devices ADD COLUMN IF NOT EXISTS model_id BIGINT REFERENCES device_models(id);
CREATE INDEX IF NOT EXISTS idx_devices_model_id ON devices(model_id) WHERE model_id IS NOT NULL;

-- ============================================
-- 2. user_device_rel 表
-- ============================================
-- 用户-设备关联表，记录用户与设备的绑定关系
-- 生产备份中已存在此表（BIGSERIAL + UNIQUE 约束），本迁移补齐 FK 约束和索引
CREATE TABLE IF NOT EXISTS user_device_rel (
    id BIGSERIAL PRIMARY KEY,
    user_id BIGINT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    device_sn VARCHAR(50) NOT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE(user_id, device_sn)
);
CREATE INDEX IF NOT EXISTS idx_user_device_rel_user ON user_device_rel(user_id);
CREATE INDEX IF NOT EXISTS idx_user_device_rel_sn ON user_device_rel(device_sn);

-- ============================================
-- 3. sync_device_timezone() 函数及触发器
-- ============================================
-- 设备 station_id 变更时自动从电站同步时区
-- 使用生产备份中的健壮版本：检查 station_id 是否实际变更 + COALESCE 默认时区
CREATE OR REPLACE FUNCTION sync_device_timezone()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.station_id IS NOT NULL AND (OLD.station_id IS NULL OR OLD.station_id != NEW.station_id) THEN
        SELECT COALESCE(s.timezone, 'Asia/Shanghai')
        INTO NEW.timezone
        FROM stations s
        WHERE s.id = NEW.station_id;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_sync_device_timezone ON devices;
CREATE TRIGGER trg_sync_device_timezone
    BEFORE INSERT OR UPDATE OF station_id ON devices
    FOR EACH ROW EXECUTE FUNCTION sync_device_timezone();

-- ---------- Migration 32: 032_fix_remaining_timestamps.up.sql ----------
-- =====================================================
-- Migration 032: 修复剩余表的 TIMESTAMP（无时区）列
-- 补充迁移 016 未覆盖的 OTA 升级相关表
-- 使用 AT TIME ZONE 'UTC' 将无时区时间戳解释为 UTC 时间
-- =====================================================

-- 1. 修复 device_upgrades 表（migration 006 创建）
--    started_at, completed_at: 可为 NULL，USING ... AT TIME ZONE 对 NULL 自动返回 NULL
--    created_at, updated_at:   NOT NULL DEFAULT NOW()
ALTER TABLE device_upgrades
    ALTER COLUMN started_at TYPE TIMESTAMPTZ USING started_at AT TIME ZONE 'UTC',
    ALTER COLUMN completed_at TYPE TIMESTAMPTZ USING completed_at AT TIME ZONE 'UTC',
    ALTER COLUMN created_at TYPE TIMESTAMPTZ USING created_at AT TIME ZONE 'UTC',
    ALTER COLUMN updated_at TYPE TIMESTAMPTZ USING updated_at AT TIME ZONE 'UTC';

-- 2. 修复 upgrade_packages 表（migration 008 创建）
ALTER TABLE upgrade_packages
    ALTER COLUMN created_at TYPE TIMESTAMPTZ USING created_at AT TIME ZONE 'UTC',
    ALTER COLUMN updated_at TYPE TIMESTAMPTZ USING updated_at AT TIME ZONE 'UTC';

-- 3. upgrade_package_items 表（migration 008 创建）
--    该表仅有 id, package_id, firmware_id, target_chip, firmware_version 列，
--    不含任何时间戳列，无需修复。

-- 4. 修复 upgrade_tasks 表（migration 009 创建）
--    scheduled_at, executed_at, completed_at: 可为 NULL
--    created_at, updated_at:                  NOT NULL DEFAULT NOW()
ALTER TABLE upgrade_tasks
    ALTER COLUMN scheduled_at TYPE TIMESTAMPTZ USING scheduled_at AT TIME ZONE 'UTC',
    ALTER COLUMN created_at TYPE TIMESTAMPTZ USING created_at AT TIME ZONE 'UTC',
    ALTER COLUMN executed_at TYPE TIMESTAMPTZ USING executed_at AT TIME ZONE 'UTC',
    ALTER COLUMN completed_at TYPE TIMESTAMPTZ USING completed_at AT TIME ZONE 'UTC',
    ALTER COLUMN updated_at TYPE TIMESTAMPTZ USING updated_at AT TIME ZONE 'UTC';

-- ---------- Migration 33: 033_create_telemetry_compat_view.up.sql ----------
-- 033: Create compatibility view mapping device_telemetry_3min typed columns
-- to the legacy device_telemetry schema, enabling read-path migration without
-- rewriting every consumer.  Also redefines v_device_latest on the new table.

-- 1. Drop the old v_device_latest (depends on device_telemetry)
DROP VIEW IF EXISTS v_device_latest;

-- 2. Compatibility view: exposes device_telemetry_3min data in the old column
--    layout so that existing SELECT queries only need a table-name swap.
--    A reconstructed `data` JSONB column preserves the nested object structure
--    (ac / batt / battery / pv / sys / sys_status / energy / data / pv_data /
--    ac_data / batt_data / energy_data) that Go consumers and
--    normalizeRealtimeData() expect.
--    Extra typed columns (daily_charge_energy, daily_discharge_energy,
--    daily_load_energy) are exposed so rewritten statistics queries can
--    reference them directly without JSONB extraction.
CREATE OR REPLACE VIEW v_device_telemetry_compat AS
SELECT
    device_sn,
    topic,
    event_time                                                       AS time,
    jsonb_build_object(
        'device_sn', device_sn,
        'ac', jsonb_build_object(
            'voltage',      ac_voltage,
            'current',      ac_current,
            'power',         ac_active_power,
            'frequency',     ac_frequency,
            'load_percent',  load_percent
        ),
        'batt', jsonb_build_object(
            'soc',          battery_soc,
            'voltage',      battery_voltage,
            'current',      battery_current,
            'power',         battery_power,
            'charge_state',  battery_state::text
        ),
        'battery', jsonb_build_object(
            'soc',          battery_soc,
            'soh',          battery_soh,
            'voltage',      battery_voltage,
            'current',      battery_current,
            'charge_state',  battery_state::text
        ),
        'pv', jsonb_build_object(
            'pv_voltage',     pv1_voltage,
            'pv_current',     pv1_current,
            'pv_power',       pv1_power,
            'pv_power_total', pv_total_power,
            'mppt_state',     mppt_state::text
        ),
        'sys', jsonb_build_object(
            'state',      work_state::text,
            'fault_code', fault_code,
            'alarm_code', alarm_code,
            'temp_inv',   inverter_temperature,
            'temp_mos',   mos_temperature,
            'efficiency', efficiency
        ),
        'sys_status', jsonb_build_object(
            'state',      work_state::text,
            'fault_code', fault_code,
            'alarm_code', alarm_code,
            'temp_inv',   inverter_temperature,
            'temp_mos',   mos_temperature,
            'efficiency', efficiency
        ),
        'energy', jsonb_build_object(
            'daily_pv',          daily_pv_energy,
            'total_pv',          total_pv_energy,
            'daily_charge',      daily_charge_energy,
            'total_charge',      total_charge_energy,
            'daily_discharge',   daily_discharge_energy,
            'total_discharge',   total_discharge_energy,
            'daily_load',        daily_load_energy,
            'total_load',        total_load_energy,
            'runtime_hours',     runtime_hours
        ),
        'data', jsonb_build_object(
            'pv_power_total',   pv_total_power,
            'power',             ac_active_power,
            'voltage',           battery_voltage,
            'current',           battery_current,
            'soc',               battery_soc,
            'daily_pv',          daily_pv_energy,
            'daily_charge',      daily_charge_energy,
            'daily_discharge',   daily_discharge_energy,
            'daily_load',        daily_load_energy,
            'total_pv',          total_pv_energy
        ),
        'pv_data',      jsonb_build_object('pv_power_total', pv_total_power),
        'ac_data',      jsonb_build_object('power', ac_active_power),
        'batt_data',    jsonb_build_object('voltage', battery_voltage, 'current', battery_current, 'soc', battery_soc),
        'energy_data',  jsonb_build_object(
            'daily_pv',        daily_pv_energy,
            'daily_charge',    daily_charge_energy,
            'daily_discharge', daily_discharge_energy,
            'daily_load',     daily_load_energy,
            'total_pv',        total_pv_energy
        ),
        'daily_energy', daily_pv_energy
    )                                                                 AS data,
    ac_active_power                                                   AS total_active_power,
    daily_pv_energy                                                   AS daily_energy,
    work_state::TEXT                                                  AS work_state,
    fault_code::TEXT                                                  AS fault_code,
    inverter_temperature                                              AS internal_temperature,
    ac_frequency                                                      AS grid_frequency,
    battery_soc,
    battery_power,
    pv_total_power                                                    AS pv_power,
    daily_charge_energy,
    daily_discharge_energy,
    daily_load_energy,
    received_at                                                       AS created_at
FROM device_telemetry_3min;

-- 3. Recreate v_device_latest on top of the compatibility view so that
--    JOIN queries (GetBySN, GetAll, etc.) keep working unchanged.
CREATE OR REPLACE VIEW v_device_latest AS
SELECT DISTINCT ON (dt.device_sn)
    dt.device_sn,
    NULL::VARCHAR                                                    AS model_code,
    dt.topic,
    dt.data,
    dt.total_active_power,
    dt.daily_energy,
    dt.work_state,
    dt.fault_code,
    dt.internal_temperature,
    dt.grid_frequency,
    dt.battery_soc,
    dt.battery_power,
    dt.pv_power,
    dt.time                                                           AS data_time,
    dt.created_at                                                     AS updated_at
FROM v_device_telemetry_compat dt
ORDER BY dt.device_sn, dt.time DESC;

