-- ---------- Migration 35: 035_unify_data_types.up.sql ----------
-- =====================================================
-- Migration 035: Unify work_state and fault_code data types
-- =====================================================
-- AUDIT FINDINGS:
--   device_telemetry.work_state   : VARCHAR(50)  (legacy table)
--   device_telemetry_3min.work_state : SMALLINT  (new table — target type)
--   device_telemetry.fault_code   : VARCHAR(50)  (legacy table)
--   device_telemetry_3min.fault_code : BIGINT    (new table — target type)
--
-- STRATEGY:
--   The new table device_telemetry_3min already uses the correct numeric
--   types (SMALLINT / BIGINT). These are the target types and remain
--   unchanged. No ALTER TABLE is needed.
--
-- GO CODE VERIFICATION:
--   inv_device_server/internal/service/protocol_parser.go:
--     Line 310: status["fault_code"] = int64(*sample.System.FaultCode)
--     Line 316: status["work_state"] = int64(*sample.System.WorkState)
--
--   The Go code already converts work_state and fault_code to int64 before
--   insertion, which is compatible with SMALLINT and BIGINT columns in
--   PostgreSQL. No Go code changes are required.
--
-- LEGACY TABLE (device_telemetry):
--   The old device_telemetry table retains VARCHAR(50) for both columns.
--   This is intentional — the legacy table is in read-only transition mode
--   and will eventually be dropped once all consumers migrate to
--   device_telemetry_3min. Altering the legacy column types would require
--   data migration (VARCHAR -> numeric) and risk data loss for any
--   non-numeric historical values.
--
-- CONCLUSION:
--   No schema changes required. This migration serves as a formal record
--   of the data type standardization decision.
-- =====================================================

-- No-op: data types are already standardized in the target table.
-- This file exists for migration audit trail purposes.

SELECT 'Migration 035: work_state/fault_code types already standardized in device_telemetry_3min (SMALLINT/BIGINT). No ALTER required.' AS status;

-- ---------- Migration 36: 036_alarms_hypertable.up.sql ----------
-- =====================================================
-- Migration 036: Convert alarms table to TimescaleDB hypertable
-- =====================================================
-- Converts the alarms table from a regular PostgreSQL table to a
-- TimescaleDB hypertable partitioned on occurred_at.
--
-- Prerequisites:
--   - TimescaleDB extension must be installed (CREATE EXTENSION IF NOT EXISTS timescaledb)
--   - Migration 027 (alarm_v1_lifecycle) must have been applied
--
-- Current alarms table structure (schema.sql + migration 027):
--   id           BIGSERIAL PRIMARY KEY
--   device_sn    VARCHAR(50) NOT NULL
--   station_id   BIGINT
--   user_id      BIGINT NOT NULL
--   alarm_level  SMALLINT NOT NULL
--   fault_code   VARCHAR(20) NOT NULL
--   fault_message VARCHAR(200) NOT NULL
--   fault_detail TEXT
--   status       SMALLINT NOT NULL DEFAULT 0
--   occurred_at  TIMESTAMPTZ NOT NULL        (already TIMESTAMPTZ — no type change needed)
--   recovered_at TIMESTAMPTZ
--   handled_at   TIMESTAMPTZ
--   handled_by   BIGINT
--   created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
--   alarm_source SMALLINT NOT NULL DEFAULT 0       (migration 027)
--   event_state  VARCHAR(16) NOT NULL DEFAULT 'active'  (migration 027)
--
-- Time columns are already TIMESTAMPTZ — no TIMESTAMP -> TIMESTAMPTZ
-- conversion is needed.
--
-- No foreign keys reference the alarms table (verified via grep).
--
-- Hypertable configuration:
--   - Partitioning column: occurred_at
--   - Chunk time interval: 7 days
--   - Compression: enabled after 30 days, segmentby device_sn
--   - Retention: retain 1 year of data
-- =====================================================

-- Ensure TimescaleDB extension is available
CREATE EXTENSION IF NOT EXISTS timescaledb;

-- =====================================================
-- Step 1: Create new table with same structure (LIKE INCLUDING ALL)
-- =====================================================
-- Use a transaction-safe approach: create alarms_new, migrate data,
-- then swap table names.

CREATE TABLE IF NOT EXISTS alarms_new (LIKE alarms INCLUDING ALL);

-- =====================================================
-- Step 2: Fix unique constraints for hypertable compatibility
-- =====================================================
-- TimescaleDB requires the partitioning column (occurred_at) to be
-- included in all unique indexes and primary keys. The original
-- primary key on (id) alone is incompatible.
-- LIKE ... INCLUDING INDEXES copies the PK as a unique index — we
-- must drop it and create a composite PK.

DO $$
DECLARE
    r RECORD;
BEGIN
    -- First drop any unique constraints on alarms_new that do NOT include occurred_at
    FOR r IN
        SELECT conname
        FROM pg_constraint c
        JOIN pg_class cl ON cl.oid = c.conrelid
        WHERE cl.relname = 'alarms_new'
          AND c.contype IN ('u', 'p')
          AND NOT EXISTS (
              SELECT 1 FROM pg_attribute a
              WHERE a.attrelid = c.conrelid
                AND a.attnum = ANY(c.conkey)
                AND a.attname = 'occurred_at'
          )
    LOOP
        EXECUTE format('ALTER TABLE alarms_new DROP CONSTRAINT IF EXISTS %I', r.conname);
        RAISE NOTICE 'Dropped constraint % for hypertable compatibility', r.conname;
    END LOOP;

    -- Then drop any remaining unique index on alarms_new that does NOT include occurred_at
    FOR r IN
        SELECT i.indexname
        FROM pg_indexes i
        WHERE i.tablename = 'alarms_new'
          AND i.indexdef ILIKE '%UNIQUE%'
          AND i.indexdef NOT ILIKE '%occurred_at%'
    LOOP
        EXECUTE format('DROP INDEX IF EXISTS %I', r.indexname);
        RAISE NOTICE 'Dropped unique index % for hypertable compatibility', r.indexname;
    END LOOP;
END $$;

-- Add composite primary key including occurred_at
ALTER TABLE alarms_new DROP CONSTRAINT IF EXISTS alarms_new_pkey;
ALTER TABLE alarms_new ADD PRIMARY KEY (id, occurred_at);

-- =====================================================
-- Step 3: Convert to hypertable (chunk_time_interval = 7 days)
-- =====================================================
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM timescaledb_information.hypertables
        WHERE hypertable_name = 'alarms_new'
    ) THEN
        PERFORM create_hypertable(
            'alarms_new',
            'occurred_at',
            chunk_time_interval => INTERVAL '7 days',
            if_not_exists => TRUE
        );
        RAISE NOTICE 'Created hypertable alarms_new on occurred_at (7-day chunks)';
    ELSE
        RAISE NOTICE 'Hypertable alarms_new already exists';
    END IF;
END $$;

-- =====================================================
-- Step 4: Migrate data from alarms to alarms_new
-- =====================================================
INSERT INTO alarms_new
SELECT * FROM alarms
ON CONFLICT (id, occurred_at) DO NOTHING;

-- =====================================================
-- Step 5: Configure compression strategy
-- =====================================================
-- Compress chunks older than 30 days, segmented by device_sn
ALTER TABLE alarms_new SET (
    timescaledb.compress,
    timescaledb.compress_segmentby = 'device_sn',
    timescaledb.compress_orderby = 'occurred_at DESC'
);

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM timescaledb_information.jobs
        WHERE proc_name = 'policy_compression'
          AND hypertable_name = 'alarms_new'
    ) THEN
        PERFORM add_compression_policy('alarms_new', INTERVAL '30 days');
        RAISE NOTICE 'Added compression policy: compress after 30 days';
    ELSE
        RAISE NOTICE 'Compression policy already exists for alarms_new';
    END IF;
END $$;

-- =====================================================
-- Step 6: Configure retention policy (retain 1 year)
-- =====================================================
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM timescaledb_information.jobs
        WHERE proc_name = 'policy_retention'
          AND hypertable_name = 'alarms_new'
    ) THEN
        PERFORM add_retention_policy('alarms_new', INTERVAL '1 year');
        RAISE NOTICE 'Added retention policy: retain 1 year';
    ELSE
        RAISE NOTICE 'Retention policy already exists for alarms_new';
    END IF;
END $$;

-- =====================================================
-- Step 7: Rename old table and swap
-- =====================================================
-- Preserve the original table as alarms_old for rollback safety.
-- The original sequence (alarms_id_seq) remains owned by alarms_old;
-- we reassign ownership to the new alarms table.

DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'alarms' AND table_type = 'BASE TABLE') THEN
        ALTER TABLE alarms RENAME TO alarms_old;
        RAISE NOTICE 'Renamed alarms -> alarms_old (backup preserved)';
    END IF;
END $$;

ALTER TABLE alarms_new RENAME TO alarms;

-- Recreate indexes with standard names on the renamed table
-- (indexes copied by INCLUDING ALL had alarms_new_ prefixed names)
CREATE INDEX IF NOT EXISTS idx_alarms_device ON alarms(device_sn);
CREATE INDEX IF NOT EXISTS idx_alarms_station ON alarms(station_id);
CREATE INDEX IF NOT EXISTS idx_alarms_user ON alarms(user_id);
CREATE INDEX IF NOT EXISTS idx_alarms_status ON alarms(status);
CREATE INDEX IF NOT EXISTS idx_alarms_time ON alarms(occurred_at);
CREATE INDEX IF NOT EXISTS idx_alarms_v1_active
    ON alarms(device_sn, alarm_source, fault_code)
    WHERE status = 0;

-- Drop duplicate indexes that were copied with alarms_new_ prefix
DROP INDEX IF EXISTS alarms_new_device_sn_idx;
DROP INDEX IF EXISTS alarms_new_station_id_idx;
DROP INDEX IF EXISTS alarms_new_user_id_idx;
DROP INDEX IF EXISTS alarms_new_status_idx;
DROP INDEX IF EXISTS alarms_new_occurred_at_idx;
DROP INDEX IF EXISTS alarms_new_device_sn_alarm_source_fault_code_idx;
-- Baseline schema may already contain migration-002's composite indexes.
-- LIKE INCLUDING ALL copies them under alarms_new_* names; remove those
-- copies so migration 039/044 can restore the canonical names without
-- retaining semantically duplicate indexes.
DROP INDEX IF EXISTS alarms_new_device_sn_created_at_idx;
DROP INDEX IF EXISTS alarms_new_status_created_at_idx;

-- Fix sequence ownership: alarms_id_seq was owned by alarms_old.id
-- Reassign to alarms.id so the new table controls the sequence
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_sequences WHERE sequencename = 'alarms_id_seq') THEN
        ALTER SEQUENCE alarms_id_seq OWNED BY alarms.id;
        RAISE NOTICE 'Reassigned alarms_id_seq ownership to alarms.id';
    END IF;
END $$;

-- Update applied_at marker
DO $$ BEGIN
    RAISE NOTICE 'Migration 036 complete: alarms is now a TimescaleDB hypertable';
END $$;

-- ---------- Migration 37: 037_fix_protocol_compliance.up.sql ----------
-- =====================================================
-- Migration 037: Fix protocol compliance issues (C-3, C-4)
-- =====================================================

-- C-3: Ensure PV field mapping matches protocol (7 fields)
DELETE FROM device_protocol_fields
WHERE protocol_version_id = (
    SELECT id FROM device_protocol_versions
    WHERE protocol_code = 'heartbeat' AND version = 1
)
AND group_code = 'pv';

INSERT INTO device_protocol_fields (
    protocol_version_id, group_code, field_index,
    field_key, wire_type, minimum, maximum
)
SELECT p.id, 'pv', m.field_index, m.field_key,
       m.wire_type::varchar, m.minimum::numeric, m.maximum::numeric
FROM device_protocol_versions p
CROSS JOIN (
    VALUES
    (0::smallint, 'pv1_voltage'::varchar, 'float32'::varchar, 0::numeric, 150::numeric),
    (1::smallint, 'pv1_current'::varchar, 'float32'::varchar, 0::numeric, 30::numeric),
    (2::smallint, 'pv1_power'::varchar,   'float32'::varchar, 0::numeric, 6200::numeric),
    (3::smallint, 'pv2_voltage'::varchar, 'float32'::varchar, 0::numeric, 150::numeric),
    (4::smallint, 'pv2_current'::varchar, 'float32'::varchar, 0::numeric, 30::numeric),
    (5::smallint, 'pv2_power'::varchar,   'float32'::varchar, 0::numeric, 6200::numeric),
    (6::smallint, 'mppt_state'::varchar,  'uint8'::varchar,   0::numeric, 2::numeric)
) AS m(field_index, field_key, wire_type, minimum, maximum)
WHERE p.protocol_code = 'heartbeat' AND p.version = 1;

-- C-4: Register 4 missing commands
INSERT INTO device_model_commands (
    model_id, command_code, display_name_key,
    parameter_schema, timeout_seconds, risk_level
)
SELECT dm.id, c.command_code, c.display_name_key,
       c.parameter_schema, c.timeout_seconds, c.risk_level
FROM device_models dm
CROSS JOIN (
    VALUES
    ('set_soc_low'::varchar,         'commands.set_soc_low'::varchar,
     '{"args":[{"key":"soc_low","type":"integer","min":0,"max":100,"unit":"%"}]}'::jsonb,
     30::integer, 2::smallint),
    ('set_soc_high'::varchar,        'commands.set_soc_high'::varchar,
     '{"args":[{"key":"soc_high","type":"integer","min":0,"max":100,"unit":"%"}]}'::jsonb,
     30::integer, 2::smallint),
    ('parallel_sync_start'::varchar, 'commands.parallel_sync_start'::varchar,
     '{"args":[]}'::jsonb,
     60::integer, 3::smallint),
    ('parallel_sync_stop'::varchar,  'commands.parallel_sync_stop'::varchar,
     '{"args":[]}'::jsonb,
     60::integer, 3::smallint)
) AS c(command_code, display_name_key, parameter_schema, timeout_seconds, risk_level)
WHERE dm.model_code = 'CS-I10-6k2'
ON CONFLICT (model_id, command_code) DO NOTHING;

-- ---------- Migration 38: 038_protocol_missing_tables.up.sql ----------
-- =====================================================
-- Migration 038: Create 5 protocol-mandated missing tables
-- =====================================================
-- Creates:
--   1. device_alarm_events      — alarm event log (hypertable, 7-day chunks)
--   2. device_alarm_snapshots   — before/after alarm snapshots
--   3. device_parallel_state    — parallel topology current state
--   4. device_parallel_events   — parallel topology change history
--   5. device_three_phase_3min  — three-phase telemetry (hypertable, 7-day chunks)
--
-- Hypertable policies:
--   device_alarm_events:     compress 30d, retain 1 year
--   device_three_phase_3min: compress 3d,  retain 90 days
-- =====================================================

CREATE EXTENSION IF NOT EXISTS timescaledb;

-- =====================================================
-- 1. device_alarm_events — alarm event log (hypertable)
-- =====================================================
-- Composite PK (id, active_at) required for TimescaleDB hypertable
-- compatibility: the partitioning column must be part of all unique
-- constraints.

CREATE TABLE IF NOT EXISTS device_alarm_events (
    id            BIGSERIAL,
    device_sn     VARCHAR(50) NOT NULL,
    station_id    BIGINT,
    source        SMALLINT NOT NULL,        -- 0 PCS, 1 BMS, 2 MPPT, 3 COMM
    code          INTEGER NOT NULL,         -- alarm code
    level         SMALLINT NOT NULL,        -- 1 warning, 2 fault
    state         SMALLINT NOT NULL,        -- 1 active, 0 recovered
    active_at     TIMESTAMPTZ NOT NULL,     -- alarm occurrence time
    recovered_at  TIMESTAMPTZ,              -- recovery time
    raw_data      JSONB,                    -- original alarm envelope
    received_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    PRIMARY KEY (id, active_at)
);

CREATE INDEX IF NOT EXISTS idx_alarm_events_device_time
    ON device_alarm_events(device_sn, active_at DESC);
CREATE INDEX IF NOT EXISTS idx_alarm_events_active
    ON device_alarm_events(device_sn, source, code) WHERE state = 1;

-- Convert to hypertable: 7-day chunks, compress after 30 days, retain 1 year
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'timescaledb') THEN
        PERFORM create_hypertable(
            'device_alarm_events',
            'active_at',
            chunk_time_interval => INTERVAL '7 days',
            if_not_exists => TRUE
        );

        ALTER TABLE device_alarm_events SET (
            timescaledb.compress,
            timescaledb.compress_segmentby = 'device_sn',
            timescaledb.compress_orderby = 'active_at DESC'
        );

        IF NOT EXISTS (
            SELECT 1 FROM timescaledb_information.jobs
            WHERE proc_name = 'policy_compression'
              AND hypertable_name = 'device_alarm_events'
        ) THEN
            PERFORM add_compression_policy('device_alarm_events', INTERVAL '30 days');
        END IF;

        IF NOT EXISTS (
            SELECT 1 FROM timescaledb_information.jobs
            WHERE proc_name = 'policy_retention'
              AND hypertable_name = 'device_alarm_events'
        ) THEN
            PERFORM add_retention_policy('device_alarm_events', INTERVAL '1 year');
        END IF;
    END IF;
END $$;

-- =====================================================
-- 2. device_alarm_snapshots — before/after alarm snapshots
-- =====================================================

CREATE TABLE IF NOT EXISTS device_alarm_snapshots (
    id                   BIGSERIAL PRIMARY KEY,
    device_sn            VARCHAR(50) NOT NULL,
    alarm_event_id       BIGINT,                  -- references device_alarm_events.id
    snapshot_type        VARCHAR(16) NOT NULL,    -- 'before' or 'after'
    ac_voltage           DOUBLE PRECISION,
    ac_current           DOUBLE PRECISION,
    ac_active_power      DOUBLE PRECISION,
    ac_frequency         DOUBLE PRECISION,
    battery_soc          DOUBLE PRECISION,
    battery_voltage      DOUBLE PRECISION,
    battery_current      DOUBLE PRECISION,
    battery_temperature  DOUBLE PRECISION,
    internal_temperature DOUBLE PRECISION,
    dc_bus_voltage       DOUBLE PRECISION,
    work_state           SMALLINT,
    fault_code           INTEGER,
    raw_snapshot         JSONB NOT NULL,          -- complete heartbeat snapshot
    captured_at          TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_alarm_snapshots_event
    ON device_alarm_snapshots(alarm_event_id);
CREATE INDEX IF NOT EXISTS idx_alarm_snapshots_device_time
    ON device_alarm_snapshots(device_sn, captured_at DESC);

-- =====================================================
-- 3. device_parallel_state — parallel topology current state
-- =====================================================

CREATE TABLE IF NOT EXISTS device_parallel_state (
    station_id          BIGINT PRIMARY KEY,
    master_sn           VARCHAR(50) NOT NULL,
    mode                VARCHAR(20) NOT NULL,      -- standalone/single_phase/three_phase
    count               SMALLINT NOT NULL DEFAULT 0,
    total_rated_power   INTEGER NOT NULL DEFAULT 0,
    total_active_power  DOUBLE PRECISION NOT NULL DEFAULT 0,
    sync_state          VARCHAR(20) NOT NULL DEFAULT 'idle',
    machines            JSONB NOT NULL DEFAULT '[]'::jsonb,
    reported_at         TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- =====================================================
-- 4. device_parallel_events — parallel topology change history
-- =====================================================

CREATE TABLE IF NOT EXISTS device_parallel_events (
    id              BIGSERIAL PRIMARY KEY,
    station_id      BIGINT NOT NULL,
    master_sn       VARCHAR(50) NOT NULL,
    event_type      VARCHAR(32) NOT NULL,          -- topology_changed/master_switched/member_added/member_removed/sync_state_changed/disabled
    mode            VARCHAR(20),
    count           SMALLINT,
    sync_state      VARCHAR(20),
    machines_before JSONB,
    machines_after  JSONB,
    occurred_at     TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_parallel_events_station_time
    ON device_parallel_events(station_id, occurred_at DESC);

-- =====================================================
-- 5. device_three_phase_3min — three-phase telemetry (hypertable)
-- =====================================================
-- Unique index (device_sn, event_time, data_hash) includes the partitioning
-- column event_time, satisfying TimescaleDB hypertable requirements.

CREATE TABLE IF NOT EXISTS device_three_phase_3min (
    device_sn           VARCHAR(50) NOT NULL,
    event_time          TIMESTAMPTZ NOT NULL,
    received_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    data_hash           VARCHAR(64) NOT NULL DEFAULT '',
    raw_envelope        JSONB NOT NULL DEFAULT '{}'::jsonb,
    voltage_l1          DOUBLE PRECISION,
    voltage_l2          DOUBLE PRECISION,
    voltage_l3          DOUBLE PRECISION,
    current_l1          DOUBLE PRECISION,
    current_l2          DOUBLE PRECISION,
    current_l3          DOUBLE PRECISION,
    active_power_l1     DOUBLE PRECISION,
    active_power_l2     DOUBLE PRECISION,
    active_power_l3     DOUBLE PRECISION,
    total_active_power  DOUBLE PRECISION,
    line_voltage_l1l2   DOUBLE PRECISION,
    line_voltage_l2l3   DOUBLE PRECISION,
    line_voltage_l3l1   DOUBLE PRECISION,
    frequency           DOUBLE PRECISION,
    voltage_unbalance   DOUBLE PRECISION,
    current_unbalance   DOUBLE PRECISION,
    quality_flags       INTEGER NOT NULL DEFAULT 0
);

-- Unique constraint for deduplication (includes partitioning column)
CREATE UNIQUE INDEX IF NOT EXISTS idx_three_phase_unique
    ON device_three_phase_3min(device_sn, event_time, data_hash);

CREATE INDEX IF NOT EXISTS idx_three_phase_device_time
    ON device_three_phase_3min(device_sn, event_time DESC);

-- Convert to hypertable: 7-day chunks, compress after 3 days, retain 90 days
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'timescaledb') THEN
        PERFORM create_hypertable(
            'device_three_phase_3min',
            'event_time',
            chunk_time_interval => INTERVAL '7 days',
            if_not_exists => TRUE
        );

        ALTER TABLE device_three_phase_3min SET (
            timescaledb.compress,
            timescaledb.compress_segmentby = 'device_sn',
            timescaledb.compress_orderby = 'event_time DESC'
        );

        IF NOT EXISTS (
            SELECT 1 FROM timescaledb_information.jobs
            WHERE proc_name = 'policy_compression'
              AND hypertable_name = 'device_three_phase_3min'
        ) THEN
            PERFORM add_compression_policy('device_three_phase_3min', INTERVAL '3 days');
        END IF;

        IF NOT EXISTS (
            SELECT 1 FROM timescaledb_information.jobs
            WHERE proc_name = 'policy_retention'
              AND hypertable_name = 'device_three_phase_3min'
        ) THEN
            PERFORM add_retention_policy('device_three_phase_3min', INTERVAL '90 days');
        END IF;
    END IF;
END $$;

-- ---------- Migration 39: 039_rebuild_alarm_parallel_three_phase.up.sql ----------
-- 039: Rebuild the protocol tables introduced by migration 038.
--
-- The five 038 tables are intentionally disposable in this migration. Core
-- business tables (users/devices/stations/model registry/OTA/work orders and
-- telemetry) are never truncated or dropped.

CREATE EXTENSION IF NOT EXISTS timescaledb;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- ---------------------------------------------------------------------------
-- 1. Keep the existing alarms data and add the compatibility columns used by
--    the current API write path. alarm_level/fault_message remain canonical.
-- ---------------------------------------------------------------------------

ALTER TABLE alarms
    ADD COLUMN IF NOT EXISTS type VARCHAR(32),
    ADD COLUMN IF NOT EXISTS level SMALLINT,
    ADD COLUMN IF NOT EXISTS message TEXT,
    ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ;

UPDATE alarms
SET type = COALESCE(type, 'device_fault'),
    level = COALESCE(level, alarm_level),
    message = COALESCE(message, fault_message),
    updated_at = COALESCE(updated_at, created_at, NOW())
WHERE type IS NULL OR level IS NULL OR message IS NULL OR updated_at IS NULL;

ALTER TABLE alarms
    ALTER COLUMN type SET DEFAULT 'device_fault',
    ALTER COLUMN type SET NOT NULL,
    ALTER COLUMN level SET NOT NULL,
    ALTER COLUMN message SET NOT NULL,
    ALTER COLUMN updated_at SET DEFAULT NOW(),
    ALTER COLUMN updated_at SET NOT NULL;

DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM alarms WHERE status NOT IN (0, 1, 2)) THEN
        RAISE EXCEPTION 'alarms contains status outside the handling-state enum 0/1/2';
    END IF;
    IF EXISTS (SELECT 1 FROM alarms WHERE event_state NOT IN ('active', 'recovered')) THEN
        RAISE EXCEPTION 'alarms contains an invalid lifecycle event_state';
    END IF;
END $$;

CREATE OR REPLACE FUNCTION normalize_alarms_compat_columns()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.status NOT IN (0, 1, 2) THEN
        RAISE EXCEPTION 'alarms.status must be 0 (unhandled), 1 (handled), or 2 (ignored)'
            USING ERRCODE = '23514';
    END IF;
    IF NEW.event_state NOT IN ('active', 'recovered') THEN
        RAISE EXCEPTION 'alarms.event_state must be active or recovered'
            USING ERRCODE = '23514';
    END IF;
    NEW.alarm_level := COALESCE(NEW.alarm_level, NEW.level);
    NEW.level := NEW.alarm_level;
    NEW.fault_message := COALESCE(NULLIF(NEW.fault_message, ''), NEW.message, '');
    NEW.message := NEW.fault_message;
    NEW.type := COALESCE(NULLIF(NEW.type, ''), 'device_fault');
    NEW.updated_at := NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_alarms_compat_columns ON alarms;
CREATE TRIGGER trg_alarms_compat_columns
BEFORE INSERT OR UPDATE ON alarms
FOR EACH ROW EXECUTE FUNCTION normalize_alarms_compat_columns();

-- Migration 036 preserved alarms_old, whose indexes retained the public
-- idx_alarms_* names. Preserve those backup indexes under explicit *_old_*
-- names before restoring the canonical names to the live hypertable.
DO $$
DECLARE
    item RECORD;
    owner_table TEXT;
BEGIN
    FOR item IN
        SELECT * FROM (VALUES
            ('idx_alarms_device',   'idx_alarms_old_device'),
            ('idx_alarms_station',  'idx_alarms_old_station'),
            ('idx_alarms_user',     'idx_alarms_old_user'),
            ('idx_alarms_status',   'idx_alarms_old_status'),
            ('idx_alarms_time',     'idx_alarms_old_time'),
            ('idx_alarms_device_time', 'idx_alarms_old_device_time'),
            ('idx_alarms_pending',  'idx_alarms_old_pending'),
            ('idx_alarms_v1_active','idx_alarms_old_v1_active')
        ) AS names(current_name, backup_name)
    LOOP
        SELECT tbl.relname INTO owner_table
        FROM pg_class idx
        JOIN pg_index pi ON pi.indexrelid = idx.oid
        JOIN pg_class tbl ON tbl.oid = pi.indrelid
        JOIN pg_namespace ns ON ns.oid = idx.relnamespace
        WHERE ns.nspname = 'public' AND idx.relname = item.current_name;

        IF owner_table = 'alarms_old' THEN
            IF to_regclass('public.' || item.backup_name) IS NOT NULL THEN
                RAISE EXCEPTION 'cannot preserve index %: target % already exists', item.current_name, item.backup_name;
            END IF;
            EXECUTE format('ALTER INDEX public.%I RENAME TO %I', item.current_name, item.backup_name);
        END IF;
        owner_table := NULL;
    END LOOP;
END $$;

CREATE INDEX IF NOT EXISTS idx_alarms_device ON alarms(device_sn);
CREATE INDEX IF NOT EXISTS idx_alarms_station ON alarms(station_id);
CREATE INDEX IF NOT EXISTS idx_alarms_user ON alarms(user_id);
CREATE INDEX IF NOT EXISTS idx_alarms_status ON alarms(status);
CREATE INDEX IF NOT EXISTS idx_alarms_time ON alarms(occurred_at DESC);
CREATE INDEX IF NOT EXISTS idx_alarms_v1_active
    ON alarms(device_sn, alarm_source, fault_code)
    WHERE event_state = 'active';

-- ---------------------------------------------------------------------------
-- 2. Drop only the five disposable 038 tables, then recreate one contract.
--    Dropping a Timescale hypertable also removes its background policies.
-- ---------------------------------------------------------------------------

DROP TABLE IF EXISTS device_alarm_snapshots CASCADE;
DROP TABLE IF EXISTS device_parallel_events CASCADE;
DROP TABLE IF EXISTS device_parallel_state CASCADE;
DROP TABLE IF EXISTS device_alarm_events CASCADE;
DROP TABLE IF EXISTS device_three_phase_3min CASCADE;

-- ---------------------------------------------------------------------------
-- 3. Alarm event log: ordinary PostgreSQL table. The compatibility trigger
--    derives the canonical event_time/t/raw/hash fields for legacy writers.
-- ---------------------------------------------------------------------------

CREATE TABLE device_alarm_events (
    id            BIGSERIAL PRIMARY KEY,
    device_sn     VARCHAR(50) NOT NULL,
    station_id    BIGINT,
    source        SMALLINT NOT NULL CHECK (source BETWEEN 0 AND 3),
    code          VARCHAR(64) NOT NULL CHECK (code <> ''),
    level         SMALLINT NOT NULL CHECK (level BETWEEN 0 AND 3),
    state         VARCHAR(16) NOT NULL CHECK (state IN ('active', 'recovered')),
    topic         VARCHAR(64) NOT NULL DEFAULT 'alarm' CHECK (topic = 'alarm'),
    event_time    TIMESTAMPTZ NOT NULL,
    t             BIGINT NOT NULL,
    active_at     TIMESTAMPTZ,
    recovered_at  TIMESTAMPTZ,
    raw_data      JSONB,
    raw_envelope  JSONB NOT NULL DEFAULT '{}'::jsonb
                  CHECK (jsonb_typeof(raw_envelope) = 'object'),
    data_hash     VARCHAR(64) NOT NULL
                  CHECK (data_hash ~ '^[0-9a-f]{64}$'),
    received_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_device_alarm_events_lifecycle
        UNIQUE (device_sn, source, code, state, event_time)
);

CREATE INDEX idx_alarm_events_device_time
    ON device_alarm_events(device_sn, event_time DESC);
CREATE INDEX idx_alarm_events_active
    ON device_alarm_events(device_sn, source, code, event_time DESC)
    WHERE state = 'active';
CREATE INDEX idx_alarm_events_station_time
    ON device_alarm_events(station_id, event_time DESC)
    WHERE station_id IS NOT NULL;

CREATE OR REPLACE FUNCTION normalize_device_alarm_event()
RETURNS TRIGGER AS $$
BEGIN
    NEW.created_at := COALESCE(NEW.created_at, NOW());
    NEW.received_at := COALESCE(NEW.received_at, NOW());
    NEW.event_time := COALESCE(NEW.event_time, NEW.active_at, NEW.recovered_at, NEW.created_at);
    NEW.t := COALESCE(NEW.t, EXTRACT(EPOCH FROM NEW.event_time)::BIGINT);
    NEW.topic := COALESCE(NULLIF(NEW.topic, ''), 'alarm');

    IF NEW.raw_envelope IS NULL OR NEW.raw_envelope = '{}'::jsonb THEN
        NEW.raw_envelope := COALESCE(NEW.raw_data, '{}'::jsonb);
    END IF;
    NEW.raw_data := COALESCE(NEW.raw_data, NEW.raw_envelope);
    NEW.data_hash := COALESCE(
        NULLIF(NEW.data_hash, ''),
        encode(digest(convert_to(NEW.raw_envelope::text, 'UTF8'), 'sha256'), 'hex')
    );

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_normalize_device_alarm_event
BEFORE INSERT OR UPDATE ON device_alarm_events
FOR EACH ROW EXECUTE FUNCTION normalize_device_alarm_event();

-- Alarm snapshots can now reference a stable, globally unique event id.
CREATE TABLE device_alarm_snapshots (
    id                   BIGSERIAL PRIMARY KEY,
    device_sn            VARCHAR(50) NOT NULL,
    alarm_event_id       BIGINT NOT NULL
                         REFERENCES device_alarm_events(id) ON DELETE CASCADE,
    snapshot_type        VARCHAR(16) NOT NULL
                         CHECK (snapshot_type IN ('before', 'after')),
    ac_voltage           DOUBLE PRECISION,
    ac_current           DOUBLE PRECISION,
    ac_active_power      DOUBLE PRECISION,
    ac_frequency         DOUBLE PRECISION,
    battery_soc          DOUBLE PRECISION,
    battery_voltage      DOUBLE PRECISION,
    battery_current      DOUBLE PRECISION,
    battery_temperature  DOUBLE PRECISION,
    internal_temperature DOUBLE PRECISION,
    dc_bus_voltage       DOUBLE PRECISION,
    work_state           SMALLINT,
    fault_code           BIGINT,
    raw_snapshot         JSONB NOT NULL DEFAULT '{}'::jsonb,
    captured_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_alarm_snapshot_event_type
        UNIQUE (alarm_event_id, snapshot_type)
);

CREATE INDEX idx_alarm_snapshots_device_time
    ON device_alarm_snapshots(device_sn, captured_at DESC);

-- ---------------------------------------------------------------------------
-- 4. Parallel current state and immutable topology events.
-- ---------------------------------------------------------------------------

CREATE TABLE device_parallel_state (
    station_id          BIGINT PRIMARY KEY REFERENCES stations(id) ON DELETE CASCADE,
    master_sn           VARCHAR(50) NOT NULL,
    enabled             BOOLEAN NOT NULL DEFAULT TRUE,
    mode                VARCHAR(20) NOT NULL DEFAULT 'standalone'
                        CHECK (mode IN ('standalone', 'single_phase', 'three_phase')),
    count               SMALLINT NOT NULL DEFAULT 0 CHECK (count BETWEEN 0 AND 8),
    total_rated_power   BIGINT NOT NULL DEFAULT 0 CHECK (total_rated_power >= 0),
    total_active_power  DOUBLE PRECISION NOT NULL DEFAULT 0
                        CHECK (total_active_power BETWEEN 0 AND 1000000000),
    sync_state          VARCHAR(20) NOT NULL DEFAULT 'idle'
                        CHECK (sync_state IN ('idle', 'synced', 'syncing', 'fault')),
    machines            JSONB NOT NULL DEFAULT '[]'::jsonb
                        CHECK (jsonb_typeof(machines) = 'array'),
    topic               VARCHAR(64) NOT NULL DEFAULT 'parallel' CHECK (topic = 'parallel'),
    event_time          TIMESTAMPTZ NOT NULL,
    t                   BIGINT NOT NULL,
    raw_envelope        JSONB NOT NULL DEFAULT '{}'::jsonb
                        CHECK (jsonb_typeof(raw_envelope) = 'object'),
    data_hash           VARCHAR(64) NOT NULL
                        CHECK (data_hash ~ '^[0-9a-f]{64}$'),
    reported_at         TIMESTAMPTZ NOT NULL,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_parallel_state_master ON device_parallel_state(master_sn);
CREATE INDEX idx_parallel_state_updated ON device_parallel_state(updated_at DESC);

CREATE OR REPLACE FUNCTION normalize_device_parallel_state()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.reported_at IS NULL OR NEW.reported_at < TIMESTAMPTZ '2000-01-01 00:00:00+00' THEN
        NEW.reported_at := COALESCE(NEW.event_time, NOW());
    END IF;
    NEW.event_time := COALESCE(NEW.event_time, NEW.reported_at);
    NEW.t := COALESCE(NEW.t, EXTRACT(EPOCH FROM NEW.event_time)::BIGINT);
    NEW.topic := COALESCE(NULLIF(NEW.topic, ''), 'parallel');
    NEW.created_at := COALESCE(NEW.created_at, NOW());
    NEW.updated_at := NOW();

    IF NEW.raw_envelope IS NULL OR NEW.raw_envelope = '{}'::jsonb THEN
        NEW.raw_envelope := jsonb_build_object(
            'v', 1,
            't', NEW.t,
            'data', jsonb_build_object(
                'enabled', NEW.enabled,
                'mode', NEW.mode,
                'count', NEW.count,
                'total_rated_power', NEW.total_rated_power,
                'total_active_power', NEW.total_active_power,
                'sync_state', NEW.sync_state,
                'machines', NEW.machines
            )
        );
    END IF;
    NEW.data_hash := COALESCE(
        NULLIF(NEW.data_hash, ''),
        encode(digest(convert_to(NEW.raw_envelope::text, 'UTF8'), 'sha256'), 'hex')
    );

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_normalize_device_parallel_state
BEFORE INSERT OR UPDATE ON device_parallel_state
FOR EACH ROW EXECUTE FUNCTION normalize_device_parallel_state();

CREATE TABLE device_parallel_events (
    id            BIGSERIAL PRIMARY KEY,
    station_id    BIGINT NOT NULL REFERENCES stations(id) ON DELETE CASCADE,
    master_sn     VARCHAR(50) NOT NULL,
    event_type    VARCHAR(32) NOT NULL CHECK (event_type IN (
                      'parallel_created', 'topology_changed', 'master_switched',
                      'member_added', 'member_removed', 'sync_state_changed', 'disabled',
                      'out_of_order'
                  )),
    old_state     JSONB,
    new_state     JSONB,
    topic         VARCHAR(64) NOT NULL DEFAULT 'parallel' CHECK (topic = 'parallel'),
    event_time    TIMESTAMPTZ NOT NULL,
    t             BIGINT NOT NULL,
    raw_envelope  JSONB NOT NULL DEFAULT '{}'::jsonb
                  CHECK (jsonb_typeof(raw_envelope) = 'object'),
    data_hash     VARCHAR(64) NOT NULL
                  CHECK (data_hash ~ '^[0-9a-f]{64}$'),
    occurred_at   TIMESTAMPTZ NOT NULL,
    created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_device_parallel_events_message
        UNIQUE (master_sn, event_time, data_hash)
);

CREATE INDEX idx_parallel_events_station_time
    ON device_parallel_events(station_id, event_time DESC);
CREATE INDEX idx_parallel_events_master_time
    ON device_parallel_events(master_sn, event_time DESC);

CREATE OR REPLACE FUNCTION normalize_device_parallel_event()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.occurred_at IS NULL OR NEW.occurred_at < TIMESTAMPTZ '2000-01-01 00:00:00+00' THEN
        NEW.occurred_at := COALESCE(NEW.event_time, NOW());
    END IF;
    NEW.event_time := COALESCE(NEW.event_time, NEW.occurred_at);
    NEW.t := COALESCE(NEW.t, EXTRACT(EPOCH FROM NEW.event_time)::BIGINT);
    NEW.topic := COALESCE(NULLIF(NEW.topic, ''), 'parallel');
    NEW.created_at := COALESCE(NEW.created_at, NOW());

    IF NEW.raw_envelope IS NULL OR NEW.raw_envelope = '{}'::jsonb THEN
        NEW.raw_envelope := jsonb_build_object(
            'v', 1,
            't', NEW.t,
            'data', jsonb_build_object(
                'event_type', NEW.event_type,
                'old_state', NEW.old_state,
                'new_state', NEW.new_state
            )
        );
    END IF;
    NEW.data_hash := COALESCE(
        NULLIF(NEW.data_hash, ''),
        encode(digest(convert_to(NEW.raw_envelope::text, 'UTF8'), 'sha256'), 'hex')
    );

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_normalize_device_parallel_event
BEFORE INSERT OR UPDATE ON device_parallel_events
FOR EACH ROW EXECUTE FUNCTION normalize_device_parallel_event();

-- ---------------------------------------------------------------------------
-- 5. Three-phase 3-minute fact hypertable.
-- ---------------------------------------------------------------------------

CREATE TABLE device_three_phase_3min (
    device_sn           VARCHAR(50) NOT NULL,
    topic               VARCHAR(64) NOT NULL DEFAULT 'three_phase' CHECK (topic = 'three_phase'),
    event_time          TIMESTAMPTZ NOT NULL,
    t                   BIGINT NOT NULL,
    received_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    data_hash           VARCHAR(64) NOT NULL
                        CHECK (data_hash ~ '^[0-9a-f]{64}$'),
    raw_envelope        JSONB NOT NULL DEFAULT '{}'::jsonb
                        CHECK (jsonb_typeof(raw_envelope) = 'object'),
    voltage_l1          DOUBLE PRECISION NOT NULL CHECK (voltage_l1 BETWEEN 0 AND 100000),
    voltage_l2          DOUBLE PRECISION NOT NULL CHECK (voltage_l2 BETWEEN 0 AND 100000),
    voltage_l3          DOUBLE PRECISION NOT NULL CHECK (voltage_l3 BETWEEN 0 AND 100000),
    current_l1          DOUBLE PRECISION NOT NULL CHECK (current_l1 BETWEEN 0 AND 100000),
    current_l2          DOUBLE PRECISION NOT NULL CHECK (current_l2 BETWEEN 0 AND 100000),
    current_l3          DOUBLE PRECISION NOT NULL CHECK (current_l3 BETWEEN 0 AND 100000),
    active_power_l1     DOUBLE PRECISION NOT NULL CHECK (active_power_l1 BETWEEN 0 AND 1000000000),
    active_power_l2     DOUBLE PRECISION NOT NULL CHECK (active_power_l2 BETWEEN 0 AND 1000000000),
    active_power_l3     DOUBLE PRECISION NOT NULL CHECK (active_power_l3 BETWEEN 0 AND 1000000000),
    total_active_power  DOUBLE PRECISION NOT NULL CHECK (total_active_power BETWEEN 0 AND 1000000000),
    line_voltage_l1l2   DOUBLE PRECISION NOT NULL CHECK (line_voltage_l1l2 BETWEEN 0 AND 100000),
    line_voltage_l2l3   DOUBLE PRECISION NOT NULL CHECK (line_voltage_l2l3 BETWEEN 0 AND 100000),
    line_voltage_l3l1   DOUBLE PRECISION NOT NULL CHECK (line_voltage_l3l1 BETWEEN 0 AND 100000),
    frequency           DOUBLE PRECISION NOT NULL CHECK (frequency BETWEEN 0 AND 1000),
    voltage_unbalance   DOUBLE PRECISION NOT NULL CHECK (voltage_unbalance BETWEEN 0 AND 100),
    current_unbalance   DOUBLE PRECISION NOT NULL CHECK (current_unbalance BETWEEN 0 AND 100),
    quality_flags       INTEGER NOT NULL DEFAULT 0 CHECK (quality_flags >= 0)
);

CREATE UNIQUE INDEX uq_three_phase_message
    ON device_three_phase_3min(device_sn, event_time, data_hash);
CREATE INDEX idx_three_phase_device_time
    ON device_three_phase_3min(device_sn, event_time DESC);

CREATE OR REPLACE FUNCTION normalize_device_three_phase_sample()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.event_time IS NULL OR NEW.event_time < TIMESTAMPTZ '2000-01-01 00:00:00+00' THEN
        NEW.event_time := NOW();
        NEW.quality_flags := NEW.quality_flags | 4;
    END IF;
    NEW.t := COALESCE(NEW.t, EXTRACT(EPOCH FROM NEW.event_time)::BIGINT);
    NEW.topic := COALESCE(NULLIF(NEW.topic, ''), 'three_phase');
    NEW.received_at := COALESCE(NEW.received_at, NOW());

    IF NEW.raw_envelope IS NULL OR NEW.raw_envelope = '{}'::jsonb THEN
        NEW.raw_envelope := jsonb_build_object(
            'v', 1,
            't', NEW.t,
            'data', jsonb_build_object(
                'voltage', jsonb_build_array(NEW.voltage_l1, NEW.voltage_l2, NEW.voltage_l3),
                'current', jsonb_build_array(NEW.current_l1, NEW.current_l2, NEW.current_l3),
                'active_power', jsonb_build_array(NEW.active_power_l1, NEW.active_power_l2, NEW.active_power_l3),
                'total_active_power', NEW.total_active_power,
                'line_voltage', jsonb_build_array(NEW.line_voltage_l1l2, NEW.line_voltage_l2l3, NEW.line_voltage_l3l1),
                'frequency', NEW.frequency,
                'voltage_unbalance', NEW.voltage_unbalance,
                'current_unbalance', NEW.current_unbalance
            )
        );
    END IF;
    NEW.data_hash := COALESCE(
        NULLIF(NEW.data_hash, ''),
        encode(digest(convert_to(NEW.raw_envelope::text, 'UTF8'), 'sha256'), 'hex')
    );

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_normalize_device_three_phase_sample
BEFORE INSERT OR UPDATE ON device_three_phase_3min
FOR EACH ROW EXECUTE FUNCTION normalize_device_three_phase_sample();

SELECT create_hypertable(
    'device_three_phase_3min',
    'event_time',
    chunk_time_interval => INTERVAL '7 days',
    if_not_exists => TRUE
);

ALTER TABLE device_three_phase_3min SET (
    timescaledb.compress,
    timescaledb.compress_segmentby = 'device_sn',
    timescaledb.compress_orderby = 'event_time DESC'
);

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM timescaledb_information.jobs
        WHERE proc_name = 'policy_compression'
          AND hypertable_schema = 'public'
          AND hypertable_name = 'device_three_phase_3min'
    ) THEN
        PERFORM add_compression_policy('device_three_phase_3min', INTERVAL '3 days');
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM timescaledb_information.jobs
        WHERE proc_name = 'policy_retention'
          AND hypertable_schema = 'public'
          AND hypertable_name = 'device_three_phase_3min'
    ) THEN
        PERFORM add_retention_policy('device_three_phase_3min', INTERVAL '90 days');
    END IF;
END $$;

COMMENT ON TABLE device_alarm_events IS 'Alarm active/recovered events; ordinary PostgreSQL table rebuilt by migration 039';
COMMENT ON TABLE device_alarm_snapshots IS 'Before/after telemetry snapshots with FK to device_alarm_events';
COMMENT ON TABLE device_parallel_state IS 'Current station-level parallel topology';
COMMENT ON TABLE device_parallel_events IS 'Immutable parallel topology changes';
COMMENT ON TABLE device_three_phase_3min IS 'Three-phase 3-minute TimescaleDB facts';

-- ---------- Migration 40: 040_protocol_runtime_contract_fixes.up.sql ----------
-- 040: Runtime contract fixes found by deployed protocol smoke tests.
-- 039 fresh installs already include this value; this migration upgrades
-- databases that applied the first 039 revision before the smoke test.

ALTER TABLE device_parallel_events
    DROP CONSTRAINT IF EXISTS device_parallel_events_event_type_check;

ALTER TABLE device_parallel_events
    ADD CONSTRAINT device_parallel_events_event_type_check
    CHECK (event_type IN (
        'parallel_created', 'topology_changed', 'master_switched',
        'member_added', 'member_removed', 'sync_state_changed', 'disabled',
        'out_of_order'
    ));

COMMENT ON CONSTRAINT device_parallel_events_event_type_check
    ON device_parallel_events IS
    'Includes out_of_order for immutable late topology snapshots that do not replace current state';

-- ---------- Migration 41: 041_restore_user_device_access_view.up.sql ----------
-- 041: Restore the canonical user-to-device access view.
--
-- The legacy view only exposed delegated bindings in user_device_rel, so a
-- device's direct owner was missing. Some upgraded databases have no view at
-- all. Keep the public two-column contract and exclude soft-deleted devices
-- for both access paths.

CREATE OR REPLACE VIEW v_user_device_access (user_id, device_sn) AS
SELECT d.user_id, d.sn
FROM devices d
WHERE d.deleted_at IS NULL
UNION
SELECT udr.user_id, d.sn
FROM user_device_rel udr
JOIN devices d ON d.sn = udr.device_sn
WHERE d.deleted_at IS NULL;

COMMENT ON VIEW v_user_device_access IS
    'Canonical object-level device access: direct ownership plus delegated bindings, excluding soft-deleted devices';

