VALUES (5, 'models', 'view', true)
ON CONFLICT (role, resource, action) DO NOTHING;

-- ---------- Migration 46: 046_drop_legacy_telemetry_tables.up.sql ----------
-- 046: retire the pre-V1 JSONB telemetry and station rollup stores.
--
-- No data is copied intentionally: the product decision permits discarding
-- legacy telemetry. All current reads are backed by device_telemetry_3min,
-- device_telemetry_hour, device_energy_day, or v_device_telemetry_compat.
-- DROP without CASCADE is deliberate: an unexpected dependency must stop the
-- migration instead of silently deleting a live view or function.

DROP TABLE IF EXISTS station_day_data;
DROP TABLE IF EXISTS device_day_data;
DROP TABLE IF EXISTS device_telemetry;

-- ---------- Migration 47: 047_namespace_telemetry_advisory_locks.up.sql ----------
-- 047: isolate advisory-lock domains for telemetry and cell derivatives.
--
-- The migration-025 functions hashed only device_sn, so independent telemetry,
-- cell, and any other same-SN writer could accidentally share one lock. Prefixes
-- preserve ordering within a stream while removing that cross-stream coupling.

CREATE OR REPLACE FUNCTION maintain_telemetry_v2_derived()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
    PERFORM pg_advisory_xact_lock(
        hashtextextended('telemetry:v1:' || NEW.device_sn, 0)
    );

    -- QualityBackfill aliases QualityOutOfOrder (bit 3 / value 8).
    -- Backfills update historical rollups, never realtime state.
    IF (NEW.quality_flags & 8) = 0 THEN
        DELETE FROM device_latest_state
        WHERE device_sn = NEW.device_sn AND event_time <= NEW.event_time;

        INSERT INTO device_latest_state
        SELECT (jsonb_populate_record(
            NULL::device_latest_state,
            to_jsonb(NEW) || jsonb_build_object('updated_at', NOW())
        )).*
        ON CONFLICT (device_sn) DO NOTHING;
    END IF;

    INSERT INTO device_energy_day(
        device_sn,stat_date,timezone,pv_energy,charge_energy,discharge_energy,load_energy,
        total_pv_energy,total_charge_energy,total_discharge_energy,total_load_energy,
        max_pv_power,max_ac_power,max_charge_power,max_discharge_power,
        avg_battery_soc,min_battery_soc,max_battery_soc,max_inverter_temperature,
        max_mos_temperature,max_battery_temperature,sample_count,online_minutes,run_minutes,quality_flags)
    SELECT NEW.device_sn,
        (NEW.event_time AT TIME ZONE COALESCE(NULLIF(d.timezone,''),'Asia/Shanghai'))::date,
        COALESCE(NULLIF(d.timezone,''),'Asia/Shanghai'),
        COALESCE(NEW.daily_pv_energy,0),COALESCE(NEW.daily_charge_energy,0),
        COALESCE(NEW.daily_discharge_energy,0),COALESCE(NEW.daily_load_energy,0),
        NEW.total_pv_energy,NEW.total_charge_energy,NEW.total_discharge_energy,NEW.total_load_energy,
        COALESCE(NEW.pv_total_power,0),COALESCE(NEW.ac_active_power,0),
        GREATEST(COALESCE(NEW.battery_power,0),0),GREATEST(-COALESCE(NEW.battery_power,0),0),
        COALESCE(NEW.battery_soc,0),COALESCE(NEW.battery_soc,0),COALESCE(NEW.battery_soc,0),
        COALESCE(NEW.inverter_temperature,0),COALESCE(NEW.mos_temperature,0),
        COALESCE(NEW.battery_temperature,0),1,3,
        CASE WHEN COALESCE(NEW.ac_active_power,0)>0 THEN 3 ELSE 0 END,NEW.quality_flags
    FROM devices d WHERE d.sn=NEW.device_sn
    ON CONFLICT(device_sn,stat_date) DO UPDATE SET
        pv_energy=GREATEST(device_energy_day.pv_energy,EXCLUDED.pv_energy),
        charge_energy=GREATEST(device_energy_day.charge_energy,EXCLUDED.charge_energy),
        discharge_energy=GREATEST(device_energy_day.discharge_energy,EXCLUDED.discharge_energy),
        load_energy=GREATEST(device_energy_day.load_energy,EXCLUDED.load_energy),
        total_pv_energy=COALESCE(EXCLUDED.total_pv_energy,device_energy_day.total_pv_energy),
        total_charge_energy=COALESCE(EXCLUDED.total_charge_energy,device_energy_day.total_charge_energy),
        total_discharge_energy=COALESCE(EXCLUDED.total_discharge_energy,device_energy_day.total_discharge_energy),
        total_load_energy=COALESCE(EXCLUDED.total_load_energy,device_energy_day.total_load_energy),
        max_pv_power=GREATEST(device_energy_day.max_pv_power,EXCLUDED.max_pv_power),
        max_ac_power=GREATEST(device_energy_day.max_ac_power,EXCLUDED.max_ac_power),
        max_charge_power=GREATEST(device_energy_day.max_charge_power,EXCLUDED.max_charge_power),
        max_discharge_power=GREATEST(device_energy_day.max_discharge_power,EXCLUDED.max_discharge_power),
        avg_battery_soc=((COALESCE(device_energy_day.avg_battery_soc,0)*device_energy_day.sample_count)+EXCLUDED.avg_battery_soc)/(device_energy_day.sample_count+1),
        min_battery_soc=LEAST(device_energy_day.min_battery_soc,EXCLUDED.min_battery_soc),
        max_battery_soc=GREATEST(device_energy_day.max_battery_soc,EXCLUDED.max_battery_soc),
        max_inverter_temperature=GREATEST(device_energy_day.max_inverter_temperature,EXCLUDED.max_inverter_temperature),
        max_mos_temperature=GREATEST(device_energy_day.max_mos_temperature,EXCLUDED.max_mos_temperature),
        max_battery_temperature=GREATEST(device_energy_day.max_battery_temperature,EXCLUDED.max_battery_temperature),
        sample_count=device_energy_day.sample_count+1,
        online_minutes=LEAST(1440,device_energy_day.online_minutes+3),
        run_minutes=LEAST(1440,device_energy_day.run_minutes+EXCLUDED.run_minutes),
        quality_flags=device_energy_day.quality_flags|EXCLUDED.quality_flags,
        updated_at=NOW();

    RETURN NEW;
END;
$$;

CREATE OR REPLACE FUNCTION maintain_latest_cells()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
    PERFORM pg_advisory_xact_lock(
        hashtextextended('cells:v1:' || NEW.device_sn, 0)
    );
    IF (NEW.quality_flags & 8) = 0 THEN
        DELETE FROM device_latest_cells
        WHERE device_sn=NEW.device_sn AND event_time<=NEW.event_time;

        INSERT INTO device_latest_cells(device_sn,event_time,sequence_no,voltages,temperatures,quality_flags,updated_at)
        VALUES(NEW.device_sn,NEW.event_time,NEW.sequence_no,NEW.voltages,NEW.temperatures,NEW.quality_flags,NOW())
        ON CONFLICT(device_sn) DO NOTHING;
    END IF;
    RETURN NEW;
END;
$$;

COMMENT ON FUNCTION maintain_telemetry_v2_derived() IS
    'Maintains latest telemetry/day energy; ordered per telemetry:v1:<device_sn> advisory-lock domain';
COMMENT ON FUNCTION maintain_latest_cells() IS
    'Maintains latest cell arrays; ordered per cells:v1:<device_sn> advisory-lock domain';

-- ---------- Migration 48: 048_p0_prerequisites.up.sql ----------
-- 026_p0_prerequisites: Register legacy system commands and add devices:control permission.
-- The systemCommands whitelist in services.go (get_params, set_params, set_control,
-- set_alarm, batch_config, reset) bypassed model-capability validation.  Before we can
-- remove that whitelist we must persist these commands into device_model_commands so the
-- standard validation path recognises them.
-- Note: restart, query_config and query_telemetry were already registered in migration 023.
-- Note: ota is handled by a dedicated OTA service path and is intentionally not registered here.

-- =============================================================
-- 1. Register missing system commands for CS-I10-6k2
-- =============================================================
WITH commands(command_code, display_name_key, parameter_schema, timeout_seconds, risk_level) AS (VALUES
    ('get_params',   'commands.get_params',   '{"args":[]}'::jsonb, 30, 1),
    ('set_params',   'commands.set_params',   '{"args":[]}'::jsonb, 30, 2),
    ('set_control',  'commands.set_control',  '{"args":[]}'::jsonb, 30, 2),
    ('set_alarm',    'commands.set_alarm',    '{"args":[]}'::jsonb, 30, 2),
    ('batch_config', 'commands.batch_config', '{"args":[]}'::jsonb, 60, 2),
    ('reset',        'commands.reset',        '{"args":[]}'::jsonb, 30, 2)
)
INSERT INTO device_model_commands (model_id, command_code, display_name_key, parameter_schema, timeout_seconds, risk_level)
SELECT dm.id, c.command_code, c.display_name_key, c.parameter_schema, c.timeout_seconds, c.risk_level
FROM device_models dm
CROSS JOIN commands c
WHERE dm.model_code = 'CS-I10-6k2'
ON CONFLICT (model_id, command_code) DO NOTHING;

-- =============================================================
-- 2. Grant devices:control permission to roles 1-4, deny for role 5
-- =============================================================
INSERT INTO role_permissions (role, resource, action, is_allowed) VALUES
    (1, 'devices', 'control', true),
    (2, 'devices', 'control', true),
    (3, 'devices', 'control', true),
    (4, 'devices', 'control', true),
    (5, 'devices', 'control', false)
ON CONFLICT (role, resource, action) DO NOTHING;

-- ---------- Migration 49: 049_extend_command_capabilities.up.sql ----------
-- 027: extend device_model_commands with fine-grained capability metadata and
-- register permission codes in role_permissions for RBAC enforcement.

-- =============================================================================
-- 1. Extend device_model_commands table with new capability columns
-- =============================================================================
ALTER TABLE device_model_commands
    ADD COLUMN IF NOT EXISTS config_domain VARCHAR(32),
    ADD COLUMN IF NOT EXISTS permission_code VARCHAR(64),
    ADD COLUMN IF NOT EXISTS operation_kind VARCHAR(20) DEFAULT 'persistent',
    ADD COLUMN IF NOT EXISTS requires_stopped BOOLEAN DEFAULT FALSE,
    ADD COLUMN IF NOT EXISTS requires_bms_online BOOLEAN DEFAULT FALSE,
    ADD COLUMN IF NOT EXISTS requires_group_master BOOLEAN DEFAULT FALSE,
    ADD COLUMN IF NOT EXISTS confirmation_mode VARCHAR(20) DEFAULT 'none',
    ADD COLUMN IF NOT EXISTS ttl_seconds INTEGER,
    ADD COLUMN IF NOT EXISTS cooldown_seconds INTEGER,
    ADD COLUMN IF NOT EXISTS precondition_schema JSONB DEFAULT '{}'::jsonb,
    ADD COLUMN IF NOT EXISTS ui_schema JSONB DEFAULT '{}'::jsonb,
    ADD COLUMN IF NOT EXISTS min_firmware VARCHAR(32);

-- =============================================================================
-- 2. Widen risk_level CHECK constraint from 1..3 to 0..4
--    (0 = info-only / read, 4 = factory-reset)
-- =============================================================================
ALTER TABLE device_model_commands DROP CONSTRAINT IF EXISTS device_model_commands_risk_level_check;
ALTER TABLE device_model_commands ADD CONSTRAINT device_model_commands_risk_level_check
    CHECK (risk_level BETWEEN 0 AND 4);

-- =============================================================================
-- 3. Backfill config_domain and permission_code for existing commands
-- =============================================================================

-- AC on/off — disruptive output control
UPDATE device_model_commands SET
    config_domain = 'output',
    permission_code = 'device_control_disruptive'
WHERE command_code IN ('ac_on', 'ac_off');

-- Power limit — basic output control
UPDATE device_model_commands SET
    config_domain = 'output',
    permission_code = 'device_control_basic'
WHERE command_code = 'set_power_limit';

-- Battery charge/discharge limits and BMS parameters — battery configuration
UPDATE device_model_commands SET
    config_domain = 'battery',
    permission_code = 'device_configure_battery'
WHERE command_code IN (
    'set_charge_limit', 'set_discharge_limit',
    'bms_set_charge_current', 'bms_set_discharge_current',
    'bms_set_charge_voltage', 'bms_set_discharge_voltage',
    'bms_set_enable'
);

-- SOC window — basic battery control
UPDATE device_model_commands SET
    config_domain = 'battery',
    permission_code = 'device_control_basic'
WHERE command_code = 'set_soc_window';

-- Force charge/discharge — disruptive battery control
UPDATE device_model_commands SET
    config_domain = 'battery',
    permission_code = 'device_control_disruptive'
WHERE command_code IN ('force_charge', 'force_discharge');

-- Restart — disruptive service operation
UPDATE device_model_commands SET
    config_domain = 'service',
    permission_code = 'device_control_disruptive'
WHERE command_code = 'restart';

-- Query / read commands — basic service operations
UPDATE device_model_commands SET
    config_domain = 'service',
    permission_code = 'device_control_basic'
WHERE command_code IN ('query_config', 'query_telemetry', 'get_params');

-- Factory reset — factory-only service operation
UPDATE device_model_commands SET
    config_domain = 'service',
    permission_code = 'device_service_factory'
WHERE command_code = 'reset';

-- Parameter write / control / alarm / batch config — disruptive service operations
UPDATE device_model_commands SET
    config_domain = 'service',
    permission_code = 'device_control_disruptive'
WHERE command_code IN ('set_params', 'set_control', 'set_alarm', 'batch_config');

-- Parallel commands — parallel configuration
UPDATE device_model_commands SET
    config_domain = 'parallel',
    permission_code = 'device_configure_parallel'
WHERE command_code IN ('parallel_enable', 'parallel_set_role', 'parallel_set_phase', 'parallel_disable');

-- =============================================================================
-- 4. Partial index for enabled commands grouped by model + domain
-- =============================================================================
CREATE INDEX IF NOT EXISTS idx_dmc_model_domain
    ON device_model_commands(model_id, config_domain)
    WHERE is_enabled = true;

-- =============================================================================
-- 5. Register fine-grained permission codes in role_permissions
--
--    Permission code              → (resource, action)
--    device_control_basic         → (device_control, basic)
--    device_control_disruptive    → (device_control, disruptive)
--    device_configure_battery     → (device_configure, battery)
--    device_configure_ac_input    → (device_configure, ac_input)
--    device_configure_parallel    → (device_configure, parallel)
--    device_service_diagnostics   → (device_service, diagnostics)
